// goiania.ts — Dados de geohashes de Goiânia para o protótipo GeoIntelligence
// Metodologia idêntica ao repositório zooxsmart-ailabs/vivo:
//   • Quadrantes: GROWTH (share<35% + sat≥6.5), UPSELL (share≥35% + sat≥7.5),
//                 RETENCAO (share≥35% + sat<6.5), GROWTH_RETENCAO (share<35% + sat<6.5)
//   • arpuRelativo: ARPU geohash / ARPU médio Goiânia (R$82)
//   • calcPriorityScore: mesmas fórmulas por quadrante
//   • Geohashes de precisão 6 centrados nos bairros reais de Goiânia

export type Quadrant = "GROWTH" | "UPSELL" | "RETENCAO" | "GROWTH_RETENCAO";
export type Technology = "FIBRA" | "MOVEL" | "AMBOS";
export type Priority = "ALTA" | "MEDIA" | "BAIXA";
export type Camada2Class =
  | "SAUDAVEL"
  | "MELHORA_QUALIDADE"
  | "AUMENTO_CAPACIDADE"
  | "EXPANSAO_NOVA_AREA"
  | "EXPANSAO_COBERTURA";

export interface Concorrente {
  nome: string;
  coberturaFibra: boolean;
  planoFibra: string;
  precoFibra: number;
  coberturaMovel: boolean;
  planoMovel: string;
  precoMovel: number;
}

export interface GeohashEntry {
  id: string;
  neighborhood: string;
  city: string;
  quadrant: Quadrant;
  isTop10: boolean;
  technology: Technology;
  lat: number;
  lng: number;
  // Satisfação comparativa
  satisfactionScores: { name: string; score: number; color: string }[];
  // Market share
  marketShare: {
    percentage: number;
    activeClients: number;
    totalPopulation: number;
    label: string;
  };
  // Tendência
  shareTrend: {
    direction: "UP" | "DOWN" | "STABLE";
    delta: number;
    deltaMovel: number;
    deltaFibra: number;
    shareMovel: number;
    shareFibra: number;
  };
  // CRM
  crm: {
    arpu: number;
    deviceTier: string;
    planType: string;
    arpuMovel: number;
    arpuFibra: number;
    planoMovel: string;
  };
  // SpeedTest
  speedtest: { downloadMbps: number; latencyMs: number; qualityLabel: string };
  // Demográficos
  demographics: {
    avgIncome: number;
    incomeLabel: string;
    populationDensity: number;
    populationGrowth: number;
    growthLabel: string;
    technology: string;
    severity: string;
  };
  // Diagnóstico
  diagnostico: {
    scoreOokla: number;
    scoreOoklaMovel: number;
    scoreOoklaFibra: number;
    scoreHAC: number;
    taxaChamados: number;
    sharePenetracao: number;
    deltaVsLider: number;
    deltaVsLiderFibra: number;
    deltaVsLiderMovel: number;
    scoreLiderFibra: number;
    scoreLiderMovel: number;
    arpuRelativo: number;
    canalDominante: string;
    canalPct: number;
    concorrentes: Concorrente[];
  };
  // Camada 2
  camada2: {
    fibra: {
      classification: Camada2Class;
      score: number;
      scoreLabel: string;
      taxaOcupacao?: number;
      portasDisponiveis?: number;
      potencialMercado?: number;
      sinergiaMovel?: number;
    };
    movel: { classification: Camada2Class; score: number; scoreLabel: string };
    decisaoIntegrada: string;
  };
  // Estratégia
  strategy: {
    title: string;
    motive: string;
    color: string;
    bgColor: string;
  };
  // Score de prioridade calculado
  priorityScore: number;
  priority: Priority;
}

// ─── DIAGNÓSTICO BIVARIADO (tooltips da legenda) ──────────────────────────────
export const DIAGNOSTICO_BIVARIADO: Record<Quadrant, { title: string; subtitle: string }> = {
  GROWTH: { title: "Share Baixo + Satisfação Alta", subtitle: "Janela de ataque, Geração de leads" },
  UPSELL: { title: "Share Alto + Satisfação Alta", subtitle: "Maximizar receita, Upsell Premium" },
  RETENCAO: { title: "Share Alto + Satisfação Baixa", subtitle: "Risco iminente de churn, Ação urgente" },
  GROWTH_RETENCAO: { title: "Share Baixo + Satisfação Baixa", subtitle: "Dupla frente: Aquisição + Infraestrutura" },
};

// ─── HELPERS ──────────────────────────────────────────────────────────────────
function calcPriority(score: number): Priority {
  if (score >= 7.5) return "ALTA";
  if (score >= 6.0) return "MEDIA";
  return "BAIXA";
}

function calcPriorityScore(
  quadrant: Quadrant,
  shareP: number,
  scoreOokla: number,
  arpuRel: number,
  taxaChamados: number
): number {
  // Mesma lógica do repositório original
  switch (quadrant) {
    case "GROWTH":
      // Peso: share baixo (oportunidade) + satisfação alta + ARPU
      return Math.min(
        10,
        (35 - shareP) * 0.15 + scoreOokla * 0.5 + arpuRel * 1.5 - taxaChamados * 0.1
      );
    case "UPSELL":
      // Peso: share alto + satisfação alta + ARPU premium
      return Math.min(
        10,
        shareP * 0.1 + scoreOokla * 0.5 + arpuRel * 2.0 - taxaChamados * 0.1
      );
    case "RETENCAO":
      // Peso: urgência (score baixo = mais urgente) + taxa chamados
      return Math.min(
        10,
        (10 - scoreOokla) * 0.8 + taxaChamados * 0.6 + shareP * 0.05
      );
    case "GROWTH_RETENCAO":
      // Peso: dupla frente — share baixo + qualidade comprometida
      return Math.min(
        10,
        (35 - shareP) * 0.1 + (10 - scoreOokla) * 0.5 + taxaChamados * 0.5
      );
  }
}

